def main():
    src = Path(sys.argv[1]) if len(sys.argv) > 1 else DEFAULT_JSON
    if not src.is_absolute():
        src = ROOT / src
    data = json.loads(src.read_text(encoding="utf-8"))
    match = re.search(r"(\d{4})-(\d{2})-(\d{2})", data.get("asof", ""))
    ymd = "".join(match.groups()) if match else "00000000"
    outdir = ROOT / "日报" / ymd
    outdir.mkdir(parents=True, exist_ok=True)
    html = TEMPLATE.replace("__DATA__", json.dumps(data, ensure_ascii=False)).replace(
        "__DATE__", data.get("asof", "")
    )
    output = outdir / f"期货形态_{ymd}.html"
    output.write_text(html, encoding="utf-8")
    print(f"完成: {len(data.get('universe', []))}品种扫描 → {output}")


if __name__ == "__main__":
    main()
